import express from 'express';
import { AdminController } from '../controllers/admin.controller';
import authenticateAndAuthorize from '@/middleware/authenticate-and-authorize';
import { Role } from '@/types/role.types';
import { TokenService } from '@/services/token.service';
import { asyncWrapper } from '@/utils/asyncWrapper';

export default function adminRoutes(adminController: AdminController) {
    const router = express.Router();

    const tokenService = new TokenService();
    router.post(
        '/login',
        asyncWrapper(adminController.adminLogin.bind(adminController))
    );

    router.post(
        '/logout',
        adminController.logout.bind(adminController) as express.RequestHandler
    );

    router.post(
        '/refresh-token',
        adminController.refreshTokenHandler.bind(adminController)
    );

    router.get(
        '/notifications',
        authenticateAndAuthorize(tokenService, [Role.Admin]),
        asyncWrapper(adminController.getNotifications.bind(adminController))
    );

    router.patch(
        '/notifications/:id/mark-read',
        authenticateAndAuthorize(tokenService, [Role.Admin]),
        asyncWrapper(
            adminController.markNotificationAsRead.bind(adminController)
        )
    );

    router.patch(
        '/notifications/mark-all-read',
        authenticateAndAuthorize(tokenService, [Role.Admin]),
        asyncWrapper(
            adminController.markAllNotificationsAsRead.bind(adminController)
        )
    );

    router.get(
        '/mentors/applications',
        authenticateAndAuthorize(tokenService, [Role.Admin]),
        asyncWrapper(
            adminController.getMentorApplications.bind(adminController)
        )
    );

    router.get(
        '/mentors/applications/:id',

        authenticateAndAuthorize(tokenService, [Role.Admin]),
        asyncWrapper(
            adminController.getMentorApplicationById.bind(adminController)
        )
    );

    router.post(
        '/mentors/applications/:id/approve',
        authenticateAndAuthorize(tokenService, [Role.Admin]),
        asyncWrapper(
            adminController.approveMentorApplication.bind(adminController)
        )
    );

    router.post(
        '/mentors/applications/:id/reject',
        authenticateAndAuthorize(tokenService, [Role.Admin]),
        asyncWrapper(
            adminController.rejectMentorApplication.bind(adminController)
        )
    );

    router.post(
        '/mentors/applications/:id/request-changes',
        authenticateAndAuthorize(tokenService, [Role.Admin]),
        asyncWrapper(
            adminController.requestChangesMentorApplication.bind(
                adminController
            )
        )
    );

    router.get(
        '/mentors',
        authenticateAndAuthorize(tokenService, [Role.Admin]),
        asyncWrapper(adminController.getAllMentors.bind(adminController))
    );

    router.get(
        '/mentors/:id',
        authenticateAndAuthorize(tokenService, [Role.Admin]),
        asyncWrapper(adminController.getMentorById.bind(adminController))
    );

    router.put(
        '/mentors/:id/status',
        authenticateAndAuthorize(tokenService, [Role.Admin]),
        asyncWrapper(adminController.updateMentorStatus.bind(adminController))
    );

    router.get(
        '/users',
        authenticateAndAuthorize(tokenService, [Role.Admin]),
        asyncWrapper(adminController.getAllUsers.bind(adminController))
    );

    router.patch(
        '/users/:id/status',
        authenticateAndAuthorize(tokenService, [Role.Admin]),
        asyncWrapper(adminController.updateUserStatus.bind(adminController))
    );

    router.get(
        '/revenue',
        authenticateAndAuthorize(tokenService, [Role.Admin]),
        asyncWrapper(adminController.getRevenueData.bind(adminController))
    );

    router.get(
        '/transactions',
        authenticateAndAuthorize(tokenService, [Role.Admin]),
        asyncWrapper(adminController.getTransactions.bind(adminController))
    );

    router.get(
        '/dashboard-stats',
        authenticateAndAuthorize(tokenService, [Role.Admin]),
        asyncWrapper(adminController.getDashboardStats.bind(adminController))
    );

    router.post(
        '/withdrawals/:walletId/transactions/:transactionId/approve',
        authenticateAndAuthorize(tokenService, [Role.Admin]),
        asyncWrapper(adminController.approveWithdrawal.bind(adminController))
    );

    router.post(
        '/withdrawals/:walletId/transactions/:transactionId/reject',
        authenticateAndAuthorize(tokenService, [Role.Admin]),
        asyncWrapper(adminController.rejectWithdrawal.bind(adminController))
    );

    return router;
}
